1	import { describe, it, expect } from "vitest";
2	
3	import { retrieveWith, RetrieverEmbeddingError } from "./retriever.js";
4	import type { Embedder } from "./embedder.js";
5	import type { SearchHit } from "./store.js";
6	import type { Chunk } from "@/db/schema";
7	import { EMBEDDING_DIM } from "@/db/schema";
8	
9	/**
10	 * In-memory embedder: maps each known string to a fixed unit vector,
11	 * unknown strings hash to a deterministic but distinct vector. Tests
12	 * pass the same string in for both the "query" and the "doc" so the
13	 * cosine distance maths stays predictable.
14	 */
15	class FakeEmbedder implements Embedder {
16	  readonly model = "fake";
17	  readonly dim = EMBEDDING_DIM;
18	  private readonly map: Map<string, number[]>;
19	  constructor(map: Record<string, number[]>) {
20	    this.map = new Map(Object.entries(map));
21	  }
22	  async embed(texts: string[]): Promise<number[][]> {
23	    return texts.map((t) => {
24	      const v = this.map.get(t);
25	      if (!v) throw new Error(`FakeEmbedder: no vector for "${t}"`);
26	      if (v.length !== this.dim) {
27	        throw new Error(
28	          `FakeEmbedder: vector for "${t}" has length ${v.length}, expected ${this.dim}`
29	        );
30	      }
31	      return v;
32	    });
33	  }
34	  getUsage() {
35	    return { totalTokens: 0, requestCount: 0 };
36	  }
37	}
38	
39	class ThrowingEmbedder implements Embedder {
40	  readonly model = "throws";
41	  readonly dim = EMBEDDING_DIM;
42	  async embed(): Promise<number[][]> {
43	    throw new Error("boom: 503 from upstream");
44	  }
45	  getUsage() {
46	    return { totalTokens: 0, requestCount: 0 };
47	  }
48	}
49	
50	function unitVec(seed: number): number[] {
51	  // Build a deterministic non-zero vector keyed by `seed`. We do NOT
52	  // need true unit length — the retriever only consumes the precomputed
53	  // similarities returned by the (faked) store.
54	  return Array.from({ length: EMBEDDING_DIM }, (_, i) =>
55	    Math.sin((i + 1) * (seed + 1) * 0.0137)
56	  );
57	}
58	
59	function makeChunk(over: Partial<Chunk> = {}): Chunk {
60	  return {
61	    id: over.id ?? "chunk-x",
62	    path: over.path ?? "corpus/x.md",
63	    contentHash: over.contentHash ?? "h",
64	    chunkIndex: over.chunkIndex ?? 0,
65	    text: over.text ?? "text",
66	    heading: over.heading ?? null,
67	    section: over.section ?? null,
68	    topics: over.topics ?? null,
69	    kind: over.kind ?? "note",
70	    date: over.date ?? null,
71	    citeOkay: over.citeOkay ?? true,
72	    voiceWeight: over.voiceWeight ?? 1.0,
73	    embedding: over.embedding ?? unitVec(0),
74	    createdAt: over.createdAt ?? new Date(),
75	  } as Chunk;
76	}
77	
78	/**
79	 * Build a fake `searchSimilar` over an array of in-memory hits. Honors
80	 * `k` (caller passes k*2) and the citeOkay filter (we deliberately do
81	 * NOT filter when citeOkay is undefined — that mirrors the retriever
82	 * spec which over-fetches both citeable and non-citeable rows).
83	 */
84	function fakeSearchOver(hits: SearchHit[]) {
85	  return async (
86	    _emb: number[],
87	    k: number,
88	    filters: { citeOkay?: boolean } = {}
89	  ): Promise<SearchHit[]> => {
90	    let pool = hits;
91	    if (filters.citeOkay !== undefined) {
92	      pool = hits.filter((h) => h.chunk.citeOkay === filters.citeOkay);
93	    }
94	    return [...pool].sort((a, b) => b.similarity - a.similarity).slice(0, k);
95	  };
96	}
97	
98	function buildFixture(): SearchHit[] {
99	  // 10 chunks with varied similarity, voiceWeight, topics, citeOkay.
100	  // Similarities are chosen so that base ranking is c0 > c1 > c2 ... > c9.
101	  return [
102	    {
103	      chunk: makeChunk({
104	        id: "c0",
105	        text: "alpha doc",
106	        topics: ["voice", "ml"],
107	        voiceWeight: 1.0,
108	      }),
109	      similarity: 0.92,
110	    },
111	    {
112	      chunk: makeChunk({
113	        id: "c1",
114	        text: "beta doc",
115	        topics: ["voice"],
116	        voiceWeight: 1.5,
117	      }),
118	      similarity: 0.86,
119	    },
120	    {
121	      chunk: makeChunk({
122	        id: "c2",
123	        text: "gamma doc",
124	        topics: ["systems"],
125	        voiceWeight: 1.0,
126	      }),
127	      similarity: 0.82,
128	    },
129	    {
130	      chunk: makeChunk({
131	        id: "c3",
132	        text: "delta doc",
133	        topics: ["ml", "research"],
134	        voiceWeight: 1.0,
135	      }),
136	      similarity: 0.78,
137	    },
138	    {
139	      chunk: makeChunk({
140	        id: "c4",
141	        text: "epsilon doc",
142	        topics: ["voice", "ml", "research"],
143	        voiceWeight: 1.0,
144	      }),
145	      similarity: 0.74,
146	    },
147	    {
148	      chunk: makeChunk({
149	        id: "c5",
150	        text: "zeta doc",
151	        topics: ["misc"],
152	        voiceWeight: 1.0,
153	      }),
154	      similarity: 0.7,
155	    },
156	    {
157	      chunk: makeChunk({
158	        id: "c6",
159	        text: "eta doc",
160	        topics: ["misc"],
161	        voiceWeight: 1.0,
162	        citeOkay: false,
163	      }),
164	      similarity: 0.68,
165	    },
166	    {
167	      chunk: makeChunk({
168	        id: "c7",
169	        text: "theta doc",
170	        topics: ["misc"],
171	        voiceWeight: 1.0,
172	      }),
173	      similarity: 0.6,
174	    },
175	    {
176	      chunk: makeChunk({
177	        id: "c8",
178	        text: "iota doc",
179	        topics: ["misc"],
180	        voiceWeight: 1.0,
181	      }),
182	      similarity: 0.56,
183	    },
184	    {
185	      chunk: makeChunk({
186	        id: "c9",
187	        text: "kappa doc",
188	        topics: ["misc"],
189	        voiceWeight: 1.0,
190	      }),
191	      similarity: 0.4, // below default minScore
192	    },
193	  ];
194	}
195	
196	describe("retrieve", () => {
197	  const embedder = new FakeEmbedder({ "any query": unitVec(0) });
198	
199	  it("returns top-k by base similarity when no boosts apply", async () => {
200	    const search = fakeSearchOver(buildFixture());
201	    const out = await retrieveWith(
202	      "any query",
203	      { k: 3, minScore: 0 },
204	      { embedder, search }
205	    );
206	    expect(out.map((r) => r.chunkId)).toEqual(["c0", "c1", "c2"]);
207	    expect(out[0].score).toBeGreaterThan(out[1].score);
208	    expect(out[1].score).toBeGreaterThan(out[2].score);
209	  });
210	
211	  it("applies voiceWeight bonus", async () => {
212	    // c1 has voiceWeight 1.5 → +0.025; with c0=0.92 vs c1=0.86+0.025=0.885,
213	    // ordering should still be c0 > c1, but c1's score should reflect bonus.
214	    const search = fakeSearchOver(buildFixture());
215	    const out = await retrieveWith(
216	      "any query",
217	      { k: 5, minScore: 0 },
218	      { embedder, search }
219	    );
220	    const c1 = out.find((r) => r.chunkId === "c1");
221	    expect(c1).toBeDefined();
222	    expect(c1!.score).toBeCloseTo(0.86 + 0.025, 5);
223	  });
224	
225	  it("topic-hint boost shifts ordering as expected", async () => {
226	    // Without hints: c0(0.92) > c1(0.86) > c2(0.82) > c3(0.78) > c4(0.74).
227	    // With hints ["voice","ml","research"]:
228	    //   c0 has voice+ml      → +0.06   → 0.98
229	    //   c1 has voice         → +0.03   → 0.86 + 0.025 (voice) +0.03 = 0.915
230	    //   c2 none              → +0      → 0.82
231	    //   c3 has ml+research   → +0.06   → 0.84
232	    //   c4 has all three     → +0.09   → 0.83
233	    // New ordering: c0 > c1 > c3 > c4 > c2  (c4 outranks c2 thanks to boost)
234	    const search = fakeSearchOver(buildFixture());
235	    const out = await retrieveWith(
236	      "any query",
237	      {
238	        k: 5,
239	        minScore: 0,
240	        topicHints: ["voice", "ml", "research"],
241	      },
242	      { embedder, search }
243	    );
244	    expect(out.map((r) => r.chunkId)).toEqual(["c0", "c1", "c3", "c4", "c2"]);
245	  });
246	
247	  it("caps the topic-hint boost at +0.10", async () => {
248	    // Six matching topics on a single chunk: bonus must clamp to 0.10
249	    // (0.03 * 6 = 0.18 raw, capped at 0.10).
250	    const hits: SearchHit[] = [
251	      {
252	        chunk: makeChunk({
253	          id: "many",
254	          topics: ["a", "b", "c", "d", "e", "f"],
255	        }),
256	        similarity: 0.6,
257	      },
258	      {
259	        chunk: makeChunk({ id: "none", topics: [] }),
260	        similarity: 0.65,
261	      },
262	    ];
263	    const search = fakeSearchOver(hits);
264	    const out = await retrieveWith(
265	      "any query",
266	      {
267	        k: 2,
268	        minScore: 0,
269	        topicHints: ["a", "b", "c", "d", "e", "f"],
270	      },
271	      { embedder, search }
272	    );
273	    const many = out.find((r) => r.chunkId === "many")!;
274	    expect(many.score).toBeCloseTo(0.6 + 0.1, 5);
275	  });
276	
277	  it("drops results below minScore", async () => {
278	    // c9 has similarity 0.4 — below default minScore of 0.55
279	    const search = fakeSearchOver(buildFixture());
280	    const out = await retrieveWith(
281	      "any query",
282	      { k: 10 },
283	      { embedder, search }
284	    );
285	    expect(out.find((r) => r.chunkId === "c9")).toBeUndefined();
286	    // c8 (sim=0.56) should survive the cut.
287	    expect(out.find((r) => r.chunkId === "c8")).toBeDefined();
288	  });
289	
290	  it("default k = 8", async () => {
291	    const search = fakeSearchOver(buildFixture());
292	    const out = await retrieveWith("any query", undefined, {
293	      embedder,
294	      search,
295	    });
296	    // 9 candidates clear the default minScore (c0..c8); k=8 caps it.
297	    expect(out).toHaveLength(8);
298	  });
299	
300	  it("returns [] when the store has no candidates", async () => {
301	    const search = fakeSearchOver([]);
302	    const out = await retrieveWith("any query", { k: 5 }, { embedder, search });
303	    expect(out).toEqual([]);
304	  });
305	
306	  it("returns [] when all candidates are below minScore", async () => {
307	    const hits: SearchHit[] = [
308	      { chunk: makeChunk({ id: "low" }), similarity: 0.1 },
309	    ];
310	    const search = fakeSearchOver(hits);
311	    const out = await retrieveWith(
312	      "any query",
313	      { k: 5, minScore: 0.55 },
314	      { embedder, search }
315	    );
316	    expect(out).toEqual([]);
317	  });
318	
319	  it("preserves citeOkay flag in the result", async () => {
320	    const search = fakeSearchOver(buildFixture());
321	    const out = await retrieveWith(
322	      "any query",
323	      { k: 10, minScore: 0 },
324	      { embedder, search }
325	    );
326	    const c6 = out.find((r) => r.chunkId === "c6");
327	    expect(c6).toBeDefined();
328	    expect(c6!.citeOkay).toBe(false);
329	    const c0 = out.find((r) => r.chunkId === "c0");
330	    expect(c0!.citeOkay).toBe(true);
331	  });
332	
333	  it("over-fetches at 2*k from the store before reranking", async () => {
334	    let observedK = 0;
335	    let observedFilters: { citeOkay?: boolean } | undefined;
336	    const fixture = buildFixture();
337	    const search = async (
338	      _emb: number[],
339	      k: number,
340	      filters: { citeOkay?: boolean } = {}
341	    ) => {
342	      observedK = k;
343	      observedFilters = filters;
344	      return [...fixture]
345	        .sort((a, b) => b.similarity - a.similarity)
346	        .slice(0, k);
347	    };
348	    await retrieveWith("any query", { k: 4 }, { embedder, search });
349	    expect(observedK).toBe(8);
350	    expect(observedFilters).toEqual({ citeOkay: undefined });
351	  });
352	
353	  it("wraps embedder failures in a typed error", async () => {
354	    const search = fakeSearchOver(buildFixture());
355	    await expect(
356	      retrieveWith(
357	        "any query",
358	        { k: 3 },
359	        { embedder: new ThrowingEmbedder(), search }
360	      )
361	    ).rejects.toBeInstanceOf(RetrieverEmbeddingError);
362	  });
363	});
